{"file_path": "/Users/mac/Documents/EaglePoint/TASK-97/TASK-meridian/repo/src/common/guards/rate-limit.guard.ts", "content": "import {
  Injectable,
  CanActivate,
  ExecutionContext,
  HttpException,
  HttpStatus,
} from '@nestjs/common';
import { AppConfigService } from '../../config/config.service';

interface RateLimitEntry {
  timestamps: number[];
}

@Injectable()
export class RateLimitGuard implements CanActivate {
  private readonly store = new Map<string, RateLimitEntry>();

  constructor(private config: AppConfigService) {}

  canActivate(context: ExecutionContext): boolean {
    const request = context.switchToHttp().getRequest();
    const ip = request.ip || request.connection?.remoteAddress || 'unknown';
    const now = Date.now();
    const windowMs = this.config.loginRateLimitWindowMs;
    const max = this.config.loginRateLimitMax;

    let entry = this.store.get(ip);
    if (!entry) {
      entry = { timestamps: [] };
      this.store.set(ip, entry);
    }

    // Sliding window: remove entries outside the window
    entry.timestamps = entry.timestamps.filter((t) => now - t < windowMs);

    if (entry.timestamps.length >= max) {
      const oldestInWindow = entry.timestamps[0];
      const retryAfterMs = windowMs - (now - oldestInWindow);
      const retryAfterSec = Math.ceil(retryAfterMs / 1000);

      throw new HttpException(
        {
          statusCode: HttpStatus.TOO_MANY_REQUESTS,
          error: 'Too Many Requests',
          message: `Rate limit exceeded. Try again in ${retryAfterSec} seconds.`,
          retryAfter: retryAfterSec,
        },
        HttpStatus.TOO_MANY_REQUESTS,
      );
    }

    entry.timestamps.push(now);
    return true;
  }

  /** Visible for testing */
  clearStore(): void {
    this.store.clear();
  }

  getAttemptCount(ip: string): number {
    const entry = this.store.get(ip);
    if (!entry) return 0;
    const now = Date.now();
    const windowMs = this.config.loginRateLimitWindowMs;
    return entry.timestamps.filter((t) => now - t < windowMs).length;
  }
}
"}

