    qb.skip((page - 1) * pageSize).take(pageSize);

    const [items, total] = await qb.getManyAndCount();
    return { items, total, page, pageSize };
  }

  async findById(id: string): Promise<AuditEvent | null> {
    return this.auditRepo.findOne({ where: { id } });
  }
}
"}

