{"file_path": "/Users/mac/Documents/EaglePoint/TASK-97/TASK-meridian/repo/src/users/users.service.ts", "content": "import { Injectable, NotFoundException } from '@nestjs/common';
import { InjectRepository } from '@nestjs/typeorm';
import { Repository } from 'typeorm';
import { User } from './user.entity';

@Injectable()
export class UsersService {
  constructor(
    @InjectRepository(User)
    private userRepo: Repository<User>,
  ) {}

  async findById(id: string): Promise<User> {
    const user = await this.userRepo.findOne({
      where: { id },
      relations: ['userRoles', 'userRoles.role'],
    });
    if (!user) throw new NotFoundException('User not found');
    return user;
  }

  async findAll(query: {
    page?: number;
    pageSize?: number;
    search?: string;
    role?: string;
    isActive?: boolean;
  }) {
    const page = query.page || 1;
    const pageSize = Math.min(query.pageSize || 20, 100);

    const qb = this.userRepo
      .createQueryBuilder('u')
      .leftJoinAndSelect('u.userRoles', 'ur')
      .leftJoinAndSelect('ur.role', 'r');

    if (query.search) {
      qb.andWhere(
        '(u.username ILIKE :search OR u.displayName ILIKE :search)',
        { search: `%${query.search}%` },
      );
    }
    if (query.role) {
      qb.andWhere('r.name = :role', { role: query.role });
    }
    if (query.isActive !== undefined) {
      qb.andWhere('u.isActive = :isActive', { isActive: query.isActive });
    }

    qb.orderBy('u.createdAt', 'DESC');
    qb.skip((page - 1) * pageSize).take(pageSize);

    const [items, total] = await qb.getManyAndCount();
    return { items, total, page, pageSize };
  }

  async updateProfile(
    userId: string,
    data: { displayName?: string; governmentId?: string; employeeId?: string },
  ): Promise<User> {
    const user = await this.findById(userId);
    if (data.displayName !== undefined) user.displayName = data.displayName;
    if (data.governmentId !== undefined) user.governmentId = data.governmentId;
    if (data.employeeId !== undefined) user.employeeId = data.employeeId;
    return this.userRepo.save(user);
  }
}
"}

