    name = name.replace(/\.\.\//g, '').replace(/\.\.\\/g, '');
    // Strip null bytes
    name = name.replace(/\0/g, '');
    // Strip control characters
    name = name.replace(/[\x00-\x1f\x7f]/g, '');
