@Controller('files')
export class FilesController {
  constructor(
    private readonly downloadTokenService: DownloadTokenService,
    private readonly filesService: FilesService,
  ) {}

  @Public()
  @Get('download')
  async download(@Query('token') token: string, @Res() res: Response) {
    const payload = this.downloadTokenService.validateToken(token);
    const stream = this.filesService.getFileStream(
      `${payload.assetId}/${payload.versionId}`,
    );
    res.setHeader('Content-Type', 'application/octet-stream');
    stream.pipe(res);
  }
}
"}

