      id,
      userId,
      idempotencyKey,
      reason,
    );
  }

  @Post(':id/approve')
  @UseGuards(RolesGuard)
  @Roles('enrollment_manager', 'admin')
  async approve(
    @Param('id') id: string,
    @Body('reason') reason: string,
    @CurrentUser('id') actorId: string,
  ) {
