  1→import {
  2→  Controller,
  3→  Post,
  4→  Body,
  5→  Req,
  6→  HttpCode,
  7→  HttpStatus,
  8→  UseGuards,
  9→  Get,
 10→} from '@nestjs/common';
 11→import { Request } from 'express';
 12→import { AuthService } from './auth.service';
 13→import { PowService } from './pow.service';
 14→import { RateLimitGuard } from '../common/guards/rate-limit.guard';
 15→import { Public } from '../common/decorators/public.decorator';
 16→import { CurrentUser } from '../common/decorators/current-user.decorator';
 17→import { IsString, IsOptional, MinLength, MaxLength, Matches } from 'class-validator';
 18→
 19→class RegisterDto {
 20→  @IsString()
 21→  @MinLength(3)
 22→  @MaxLength(255)
 23→  @Matches(/^[a-zA-Z0-9_]+$/, { message: 'Username must be alphanumeric with underscores' })
 24→  username: string;
 25→
 26→  @IsString()
 27→  @MinLength(12)
 28→  password: string;
 29→
 30→  @IsString()
 31→  @MinLength(1)
 32→  @MaxLength(255)
 33→  displayName: string;
 34→
 35→  @IsString()
 36→  challengeId: string;
 37→
 38→  @IsString()
 39→  nonce: string;
 40→}
 41→
 42→class LoginDto {
 43→  @IsString()
 44→  username: string;
 45→
 46→  @IsString()
 47→  password: string;
 48→
 49→  @IsOptional()
 50→  @IsString()
 51→  challengeId?: string;
 52→
 53→  @IsOptional()
 54→  @IsString()
 55→  nonce?: string;
 56→}
 57→
 58→class ChangePasswordDto {
 59→  @IsString()
 60→  currentPassword: string;
 61→
 62→  @IsString()
 63→  @MinLength(12)
 64→  newPassword: string;
 65→}
 66→
 67→class ResetPasswordDto {
 68→  @IsString()
 69→  token: string;
 70→
 71→  @IsString()
 72→  @MinLength(12)
 73→  newPassword: string;
 74→
 75→  @IsString()
 76→  challengeId: string;
 77→
 78→  @IsString()
 79→  nonce: string;
 80→}
 81→
 82→@Controller('auth')
 83→export class AuthController {
 84→  constructor(
 85→    private readonly authService: AuthService,
 86→    private readonly powService: PowService,
 87→    private readonly rateLimitGuard: RateLimitGuard,
 88→  ) {}
 89→
 90→  @Public()
 91→  @Get('challenge')
 92→  async getChallenge() {
 93→    return this.powService.createChallenge();
 94→  }
 95→
 96→  @Public()
 97→  @Post('register')
 98→  async register(@Body() dto: RegisterDto) {
 99→    await this.powService.validateChallenge(dto.challengeId, dto.nonce);
100→    return this.authService.register({
101→      username: dto.username,
102→      password: dto.password,
103→      displayName: dto.displayName,
104→    });
105→  }
106→
107→  @Public()
108→  @Post('login')
109→  @UseGuards(RateLimitGuard)
110→  async login(@Body() dto: LoginDto, @Req() req: Request) {
111→    const ip = req.ip || req.socket?.remoteAddress || 'unknown';
112→    const userAgent = req.headers['user-agent'];
113→
114→    // Check if PoW required (after 3 failures for the account)
115→    if (dto.challengeId && dto.nonce) {
116→      await this.powService.validateChallenge(dto.challengeId, dto.nonce);
117→    }
118→
119→    return this.authService.login(dto.username, dto.password, ip, userAgent);
120→  }
121→
122→  @Post('logout')
123→  @HttpCode(HttpStatus.NO_CONTENT)
124→  async logout(@Req() req: Request) {
125→    const token = req.headers.authorization?.slice(7);
126→    if (token) {
127→      await this.authService.logout(token);
128→    }
129→  }
130→
131→  @Post('change-password')
132→  @HttpCode(HttpStatus.NO_CONTENT)
133→  async changePassword(
134→    @CurrentUser('id') userId: string,
135→    @Body() dto: ChangePasswordDto,
136→  ) {
137→    await this.authService.changePassword(
138→      userId,
139→      dto.currentPassword,
140→      dto.newPassword,
141→    );
142→  }
143→
144→  @Public()
145→  @Post('reset-password')
146→  async resetPassword(@Body() dto: ResetPasswordDto) {
147→    await this.powService.validateChallenge(dto.challengeId, dto.nonce);
148→    await this.authService.redeemResetToken(dto.token, dto.newPassword);
149→  }
150→}
