  Controller,
  Get,
  Post,
  Put,
  Param,
  Body,
  Query,
  UseGuards,
  UseInterceptors,
  UploadedFile,
  BadRequestException,
} from '@nestjs/common';
import { FileInterceptor } from '@nestjs/platform-express';
import { ContentService } from './content.service';
import { CurrentUser } from '../common/decorators/current-user.decorator';
import { Roles } from '../common/decorators/roles.decorator';
import { RolesGuard } from '../common/guards/roles.guard';
import { AssetType } from './content-asset.entity';
import { DuplicateDetectionService } from '../duplicate-detection/duplicate-detection.service';
import { ParsingService } from '../parsed-documents/parsing.service';
import { memoryStorage } from 'multer';

@Controller('content-assets')
export class ContentController {
  constructor(
    private readonly contentService: ContentService,
    private readonly duplicateService: DuplicateDetectionService,
    private readonly parsingService: ParsingService,
  ) {}

  @Post()
  @UseGuards(RolesGuard)
  @Roles('content_manager', 'admin')
  @UseInterceptors(
    FileInterceptor('file', {
      storage: memoryStorage(),
      limits: { fileSize: 250 * 1024 * 1024 },
    }),
  )
  async create(
    @UploadedFile() file: Express.Multer.File,
    @Body('title') title: string,
    @Body('assetType') assetType: AssetType,
    @Body('author') author: string,
    @Body('publisher') publisher: string,
    @Body('effectiveFrom') effectiveFrom: string,
    @Body('effectiveTo') effectiveTo: string,
    @Body('categoryIds') categoryIds: string,
    @Body('tagIds') tagIds: string,
    @CurrentUser('id') userId: string,
  ) {
    if (!file) {
      throw new BadRequestException('File is required');
    }
    if (!title || !assetType) {
      throw new BadRequestException('Title and assetType are required');
    }
    return this.contentService.createAsset(file, {
      title,
      assetType,
      author,
      publisher,
      effectiveFrom: effectiveFrom ? new Date(effectiveFrom) : undefined,
      effectiveTo: effectiveTo ? new Date(effectiveTo) : undefined,
      categoryIds: categoryIds ? JSON.parse(categoryIds) : undefined,
      tagIds: tagIds ? JSON.parse(tagIds) : undefined,
    }, userId);
  }

  @Get()
  async findAll(
    @Query('page') page?: number,
    @Query('pageSize') pageSize?: number,
    @Query('search') search?: string,
    @Query('assetType') assetType?: string,
    @Query('categoryId') categoryId?: string,
    @Query('tagId') tagId?: string,
    @Query('author') author?: string,
  ) {
    return this.contentService.findAll({
      page, pageSize, search, assetType, categoryId, tagId, author,
    });
  }

  @Get(':id')
  async findOne(@Param('id') id: string) {
    return this.contentService.findById(id);
  }

  @Put(':id')
  @UseGuards(RolesGuard)
  @Roles('content_manager', 'admin')
  @UseInterceptors(
    FileInterceptor('file', {
      storage: memoryStorage(),
      limits: { fileSize: 250 * 1024 * 1024 },
    }),
  )
  async update(
    @Param('id') id: string,
    @UploadedFile() file: Express.Multer.File,
    @Body('title') title: string,
    @Body('author') author: string,
    @Body('publisher') publisher: string,
    @Body('effectiveFrom') effectiveFrom: string,
    @Body('effectiveTo') effectiveTo: string,
    @Body('bumpMajor') bumpMajor: string,
    @CurrentUser('id') userId: string,
  ) {
    return this.contentService.updateAsset(id, file, {
      title,
      author,
      publisher,
      effectiveFrom: effectiveFrom ? new Date(effectiveFrom) : undefined,
      effectiveTo: effectiveTo ? new Date(effectiveTo) : undefined,
      bumpMajor: bumpMajor === 'true',
    }, userId);
  }

  @Get(':id/versions')
  async getVersions(@Param('id') id: string) {
    return this.contentService.getVersions(id);
  }

  @Get(':id/versions/:versionId')
  async getVersion(
    @Param('id') id: string,
    @Param('versionId') versionId: string,
  ) {
    return this.contentService.getVersion(id, versionId);
  }

  @Post(':id/rollback')
  @UseGuards(RolesGuard)
  @Roles('content_manager', 'admin')
  async rollback(
    @Param('id') id: string,
    @Body('targetVersionId') targetVersionId: string,
    @CurrentUser('id') userId: string,
  ) {
    if (!targetVersionId) {
      throw new BadRequestException('targetVersionId is required');
    }
    return this.contentService.rollback(id, targetVersionId, userId);
  }

  @Get(':id/versions/:versionId/download-token')
  async getDownloadToken(
    @Param('id') id: string,
    @Param('versionId') versionId: string,
    @CurrentUser('id') userId: string,
  ) {
    return this.contentService.getDownloadToken(id, versionId, userId);
  }

  @Post(':id/merge')
  @UseGuards(RolesGuard)
  @Roles('admin')
  async merge(
    @Param('id') id: string,
    @Body('sourceIds') sourceIds: string[],
    @Body('canonicalId') canonicalId: string,
    @CurrentUser('id') userId: string,
  ) {
    if (!sourceIds?.length || !canonicalId) {
      throw new BadRequestException('sourceIds and canonicalId are required');
    }
    return this.duplicateService.mergeCanonical(sourceIds, canonicalId, userId);
  }

  @Get(':id/parsed')
  async getParsedDocuments(@Param('id') id: string) {
    const asset = await this.contentService.findById(id);
    const currentVersion = asset.versions?.find((v) => v.isCurrent);
    if (!currentVersion) return [];
    return this.parsingService.findByVersionId(currentVersion.id);
  }

  @Get(':id/duplicates')
  @UseGuards(RolesGuard)
  @Roles('content_manager', 'admin')
  async getDuplicates(@Param('id') id: string) {
    return this.contentService.getDuplicateLinks(id);
  }

  @Get(':id/lineage')
  async getLineage(@Param('id') id: string) {
    return this.contentService.getLineage(id);
  }
}
"}

