300→  async findAll(query: {
301→    page?: number;
302→    pageSize?: number;
303→    search?: string;
304→    assetType?: string;
305→    categoryId?: string;
306→    tagId?: string;
307→    author?: string;
308→  }) {
309→    const page = query.page || 1;
310→    const pageSize = Math.min(query.pageSize || 20, 100);
311→
312→    const qb = this.assetRepo
313→      .createQueryBuilder('ca')
314→      .leftJoinAndSelect('ca.versions', 'v', 'v.isCurrent = true')
315→      .leftJoinAndSelect('ca.categories', 'cat')
316→      .leftJoinAndSelect('ca.tags', 'tag');
317→
318→    if (query.search) {
319→      qb.andWhere('(ca.title ILIKE :s OR ca.author ILIKE :s)', {
320→        s: `%${query.search}%`,
321→      });
322→    }
323→    if (query.assetType) {
324→      qb.andWhere('ca.assetType = :at', { at: query.assetType });
325→    }
326→    if (query.author) {
327→      qb.andWhere('ca.author ILIKE :author', { author: `%${query.author}%` });
328→    }
329→
330→    qb.orderBy('ca.updatedAt', 'DESC');
331→    qb.skip((page - 1) * pageSize).take(pageSize);
332→
333→    const [items, total] = await qb.getManyAndCount();
334→    return { items, total, page, pageSize };
335→  }
