380→  private bumpVersion(
381→    current: string,
382→    level: 'patch' | 'minor' | 'major',
383→    forceMajor: boolean,
384→  ): string {
385→    const [major, minor, patch] = current.split('.').map(Number);
386→    if (forceMajor) return `${major + 1}.0.0`;
387→    if (level === 'major') return `${major + 1}.0.0`;
388→    if (level === 'minor') return `${major}.${minor + 1}.0`;
389→    return `${major}.${minor}.${patch + 1}`;
390→  }
391→}
