  1→import { Injectable } from '@nestjs/common';
  2→import { InjectRepository } from '@nestjs/typeorm';
  3→import { Repository } from 'typeorm';
  4→import { DuplicateGroup } from './duplicate-group.entity';
  5→import { DuplicateLink } from './duplicate-link.entity';
  6→import { CanonicalLink } from './canonical-link.entity';
  7→import { ParsedDocument } from '../parsed-documents/parsed-document.entity';
  8→import { createHash } from 'crypto';
  9→import { AuditService } from '../audit/audit.service';
 10→
 11→const SHINGLE_SIZE = 5; // 5-word shingles
 12→const MINHASH_PERMUTATIONS = 128;
 13→const SIMILARITY_THRESHOLD = 0.8;
 14→
 15→@Injectable()
 16→export class DuplicateDetectionService {
 17→  constructor(
 18→    @InjectRepository(DuplicateGroup)
 19→    private groupRepo: Repository<DuplicateGroup>,
 20→    @InjectRepository(DuplicateLink)
 21→    private linkRepo: Repository<DuplicateLink>,
 22→    @InjectRepository(CanonicalLink)
 23→    private canonicalRepo: Repository<CanonicalLink>,
 24→    @InjectRepository(ParsedDocument)
 25→    private parsedDocRepo: Repository<ParsedDocument>,
 26→    private auditService: AuditService,
 27→  ) {}
 28→
 29→  /**
 30→   * Detect exact duplicates by content hash.
 31→   */
 32→  async detectExactDuplicates(documentId: string): Promise<DuplicateLink[]> {
 33→    const doc = await this.parsedDocRepo.findOne({
 34→      where: { id: documentId },
 35→    });
 36→    if (!doc) return [];
 37→
 38→    const duplicates = await this.parsedDocRepo.find({
 39→      where: { contentHash: doc.contentHash },
 40→    });
 41→
 42→    const links: DuplicateLink[] = [];
 43→    for (const dup of duplicates) {
 44→      if (dup.id === doc.id) continue;
 45→
 46→      // Check if link already exists
 47→      const existing = await this.linkRepo.findOne({
 48→        where: [
 49→          { docAId: doc.id, docBId: dup.id },
 50→          { docAId: dup.id, docBId: doc.id },
 51→        ],
 52→      });
 53→      if (existing) continue;
 54→
 55→      const link = this.linkRepo.create({
 56→        docAId: doc.id,
 57→        docBId: dup.id,
 58→        similarityScore: 1.0,
 59→      });
 60→      links.push(await this.linkRepo.save(link));
 61→    }
 62→
 63→    return links;
 64→  }
 65→
 66→  /**
 67→   * Detect near-duplicates using MinHash/shingle overlap.
 68→   */
 69→  async detectNearDuplicates(documentId: string): Promise<DuplicateLink[]> {
 70→    const doc = await this.parsedDocRepo.findOne({
 71→      where: { id: documentId },
 72→    });
 73→    if (!doc) return [];
 74→
 75→    const docShingles = this.generateShingles(doc.contentText);
 76→    const docMinHash = this.computeMinHash(docShingles);
 77→
 78→    // Compare against all other documents
 79→    const allDocs = await this.parsedDocRepo.find();
 80→    const links: DuplicateLink[] = [];
 81→
 82→    for (const other of allDocs) {
 83→      if (other.id === doc.id) continue;
 84→      if (other.contentHash === doc.contentHash) continue; // Already caught by exact
 85→
 86→      const otherShingles = this.generateShingles(other.contentText);
 87→      const otherMinHash = this.computeMinHash(otherShingles);
 88→
 89→      const similarity = this.estimateJaccard(docMinHash, otherMinHash);
 90→
 91→      if (similarity >= SIMILARITY_THRESHOLD) {
 92→        const existing = await this.linkRepo.findOne({
 93→          where: [
 94→            { docAId: doc.id, docBId: other.id },
 95→            { docAId: other.id, docBId: doc.id },
 96→          ],
 97→        });
 98→        if (existing) continue;
 99→
100→        const link = this.linkRepo.create({
101→          docAId: doc.id,
102→          docBId: other.id,
103→          similarityScore: similarity,
104→        });
105→        links.push(await this.linkRepo.save(link));
106→      }
107→    }
108→
109→    return links;
110→  }
111→
112→  /**
113→   * Designate a canonical record from a set of duplicates.
114→   */
115→  async mergeCanonical(
116→    sourceAssetIds: string[],
117→    canonicalAssetId: string,
118→    userId: string,
119→  ): Promise<CanonicalLink[]> {
120→    const links: CanonicalLink[] = [];
121→
122→    for (const sourceId of sourceAssetIds) {
123→      if (sourceId === canonicalAssetId) continue;
124→
125→      const existing = await this.canonicalRepo.findOne({
126→        where: { sourceAssetId: sourceId },
127→      });
128→      if (existing) continue;
129→
130→      const link = this.canonicalRepo.create({
131→        sourceAssetId: sourceId,
132→        canonicalAssetId,
133→        mergedBy: userId,
134→      });
135→      links.push(await this.canonicalRepo.save(link));
136→    }
137→
138→    await this.auditService.recordEvent({
139→      action: 'duplicate.merge',
140→      resourceType: 'content_assets',
141→      resourceId: canonicalAssetId,
142→      actorId: userId,
143→      changes: { sourceAssetIds, canonicalAssetId },
144→    });
145→
146→    return links;
147→  }
148→
149→  /**
150→   * Generate w-word shingles from text.
151→   */
152→  generateShingles(text: string): Set<string> {
153→    const words = text.toLowerCase().split(/\s+/).filter(Boolean);
154→    const shingles = new Set<string>();
155→    for (let i = 0; i <= words.length - SHINGLE_SIZE; i++) {
156→      shingles.add(words.slice(i, i + SHINGLE_SIZE).join(' '));
157→    }
158→    return shingles;
159→  }
160→
161→  /**
162→   * Compute MinHash signature for a set of shingles.
163→   */
164→  computeMinHash(shingles: Set<string>): number[] {
165→    const signature: number[] = new Array(MINHASH_PERMUTATIONS).fill(Infinity);
166→
167→    for (const shingle of shingles) {
168→      for (let i = 0; i < MINHASH_PERMUTATIONS; i++) {
169→        const hash = this.hashShingle(shingle, i);
170→        if (hash < signature[i]) {
171→          signature[i] = hash;
172→        }
173→      }
174→    }
175→
176→    return signature;
177→  }
178→
179→  /**
180→   * Estimate Jaccard similarity from two MinHash signatures.
181→   */
182→  estimateJaccard(sig1: number[], sig2: number[]): number {
183→    let matches = 0;
184→    for (let i = 0; i < sig1.length; i++) {
185→      if (sig1[i] === sig2[i]) matches++;
186→    }
187→    return matches / sig1.length;
188→  }
189→
190→  private hashShingle(shingle: string, seed: number): number {
191→    const hash = createHash('sha256')
192→      .update(`${seed}:${shingle}`)
193→      .digest();
194→    // Use first 4 bytes as a 32-bit integer
195→    return hash.readUInt32BE(0);
196→  }
197→
198→  async getDuplicateLinks(documentId: string): Promise<DuplicateLink[]> {
199→    return this.linkRepo.find({
200→      where: [{ docAId: documentId }, { docBId: documentId }],
201→    });
202→  }
203→}
