  1→import { Injectable } from '@nestjs/common';
  2→import { InjectRepository } from '@nestjs/typeorm';
  3→import { Repository } from 'typeorm';
  4→import { ParsedDocument } from './parsed-document.entity';
  5→import { createHash } from 'crypto';
  6→
  7→interface ParsedChapter {
  8→  index: number;
  9→  title: string | null;
 10→  text: string;
 11→}
 12→
 13→@Injectable()
 14→export class ParsingService {
 15→  constructor(
 16→    @InjectRepository(ParsedDocument)
 17→    private parsedDocRepo: Repository<ParsedDocument>,
 18→  ) {}
 19→
 20→  async parseAndStore(
 21→    versionId: string,
 22→    fileBuffer: Buffer,
 23→    mimeType: string,
 24→  ): Promise<ParsedDocument[]> {
 25→    let chapters: ParsedChapter[];
 26→
 27→    if (mimeType.includes('pdf') || mimeType.includes('application/pdf')) {
 28→      chapters = await this.parsePdf(fileBuffer);
 29→    } else if (mimeType.includes('epub')) {
 30→      chapters = await this.parseEpub(fileBuffer);
 31→    } else if (mimeType.includes('text/plain')) {
 32→      chapters = this.parsePlainText(fileBuffer);
 33→    } else {
 34→      // Non-text formats (mp4, mp3) — no text extraction
 35→      return [];
 36→    }
 37→
 38→    const docs: ParsedDocument[] = [];
 39→    for (const chapter of chapters) {
 40→      const normalized = this.normalizeText(chapter.text);
 41→      const contentHash = createHash('sha256').update(normalized).digest('hex');
 42→
 43→      const doc = this.parsedDocRepo.create({
 44→        versionId,
 45→        chapterIndex: chapter.index,
 46→        title: chapter.title,
 47→        contentText: chapter.text,
 48→        contentHash,
 49→      });
 50→      docs.push(await this.parsedDocRepo.save(doc));
 51→    }
 52→
 53→    return docs;
 54→  }
 55→
 56→  normalizeText(text: string): string {
 57→    return text
 58→      .toLowerCase()
 59→      .replace(/[^\w\s]/g, '') // remove punctuation
 60→      .replace(/\s+/g, ' ') // collapse whitespace
 61→      .trim();
 62→  }
 63→
 64→  computeContentHash(text: string): string {
 65→    const normalized = this.normalizeText(text);
 66→    return createHash('sha256').update(normalized).digest('hex');
 67→  }
 68→
 69→  private async parsePdf(buffer: Buffer): Promise<ParsedChapter[]> {
 70→    try {
 71→      const pdfParse = require('pdf-parse');
 72→      const data = await pdfParse(buffer);
 73→
 74→      // Split by page markers or double newlines
 75→      const pages = data.text.split(/\n{3,}/);
 76→      return pages
 77→        .filter((p: string) => p.trim().length > 0)
 78→        .map((text: string, index: number) => ({
 79→          index,
 80→          title: `Page ${index + 1}`,
 81→          text: text.trim(),
 82→        }));
 83→    } catch {
 84→      return [
 85→        { index: 0, title: 'Document', text: buffer.toString('utf8', 0, Math.min(buffer.length, 10000)) },
 86→      ];
 87→    }
 88→  }
 89→
 90→  private async parseEpub(buffer: Buffer): Promise<ParsedChapter[]> {
 91→    try {
 92→      // epub2 expects a file path, so we work with the buffer content
 93→      // For now, extract text from the ZIP structure
 94→      const content = buffer.toString('utf8');
 95→      // Basic extraction: find text between XML tags
 96→      const textBlocks = content.match(/<p[^>]*>([^<]+)<\/p>/gi) || [];
 97→      const text = textBlocks
 98→        .map((block) => block.replace(/<[^>]+>/g, '').trim())
 99→        .filter((t) => t.length > 0)
100→        .join('\n\n');
101→
102→      if (text.length > 0) {
103→        const paragraphs = text.split(/\n{2,}/);
104→        const chapterSize = Math.max(1, Math.ceil(paragraphs.length / 10));
105→        const chapters: ParsedChapter[] = [];
106→        for (let i = 0; i < paragraphs.length; i += chapterSize) {
107→          chapters.push({
108→            index: chapters.length,
109→            title: `Chapter ${chapters.length + 1}`,
110→            text: paragraphs.slice(i, i + chapterSize).join('\n\n'),
111→          });
112→        }
113→        return chapters;
114→      }
115→      return [{ index: 0, title: 'Document', text: 'No extractable text content' }];
116→    } catch {
117→      return [{ index: 0, title: 'Document', text: 'Parse error' }];
118→    }
119→  }
120→
121→  private parsePlainText(buffer: Buffer): ParsedChapter[] {
122→    const text = buffer.toString('utf8');
123→    const sections = text.split(/\n{2,}/);
124→
125→    if (sections.length <= 1) {
126→      return [{ index: 0, title: 'Document', text: text.trim() }];
127→    }
128→
129→    return sections
130→      .filter((s) => s.trim().length > 0)
131→      .map((section, index) => ({
132→        index,
133→        title: `Section ${index + 1}`,
134→        text: section.trim(),
135→      }));
136→  }
137→
138→  async findByVersionId(versionId: string): Promise<ParsedDocument[]> {
139→    return this.parsedDocRepo.find({
140→      where: { versionId },
141→      order: { chapterIndex: 'ASC' },
142→    });
143→  }
144→}
