  9→import { InjectRepository } from '@nestjs/typeorm';
 10→import { Repository, DataSource, Not } from 'typeorm';
 11→import { Enrollment, EnrollmentStatus } from './enrollment.entity';
 12→import { EnrollmentStateTransition } from './enrollment-state-transition.entity';
 13→import { Reservation, ReservationStatus } from '../reservations/reservation.entity';
 14→import { Offering } from '../offerings/offering.entity';
 15→import { IdempotencyService } from '../idempotency/idempotency.service';
 16→import { AuditService } from '../audit/audit.service';
 17→import { getTraceId } from '../common/interceptors/trace-id.interceptor';
 18→
 19→@Injectable()
 20→export class EnrollmentsService {
 21→  constructor(
 22→    @InjectRepository(Enrollment)
 23→    private enrollmentRepo: Repository<Enrollment>,
 24→    @InjectRepository(EnrollmentStateTransition)
 25→    private transitionRepo: Repository<EnrollmentStateTransition>,
 26→    private idempotencyService: IdempotencyService,
 27→    private auditService: AuditService,
 28→    private dataSource: DataSource,
 29→  ) {}
