 31→  async confirmReservation(
 32→    reservationId: string,
 33→    userId: string,
 34→    idempotencyKey: string,
 35→  ) {
 36→    const idempCheck = await this.idempotencyService.check(
 37→      idempotencyKey,
 38→      'enrollments.confirm',
 39→      userId,
 40→    );
 41→    if (idempCheck.isDuplicate) {
 42→      return idempCheck.storedResponse!.body;
 43→    }
 44→
 45→    return this.dataSource.transaction(async (manager) => {
 46→      const reservation = await manager
 47→        .createQueryBuilder(Reservation, 'r')
 48→        .setLock('pessimistic_write')
 49→        .where('r.id = :id', { id: reservationId })
 50→        .getOne();
 51→
 52→      if (!reservation) {
 53→        throw new NotFoundException('Reservation not found');
 54→      }
 55→
 56→      if (reservation.userId !== userId) {
 57→        throw new BadRequestException('Reservation does not belong to you');
 58→      }
 59→
 60→      if (reservation.status !== ReservationStatus.HELD) {
 61→        throw new BadRequestException('Reservation is not in HELD status');
 62→      }
 63→
 64→      if (reservation.expiresAt < new Date()) {
 65→        throw new HttpException(
 66→          'Reservation has expired',
 67→          HttpStatus.GONE,
 68→        );
 69→      }
 70→
 71→      // Check for duplicate enrollment
 72→      const existingEnrollment = await manager
 73→        .createQueryBuilder(Enrollment, 'e')
 74→        .where('e.offeringId = :offeringId', {
 75→          offeringId: reservation.offeringId,
 76→        })
 77→        .andWhere('e.userId = :userId', { userId })
 78→        .andWhere("e.status != :canceled", {
 79→          canceled: EnrollmentStatus.CANCELED,
 80→        })
 81→        .getOne();
 82→
 83→      if (existingEnrollment) {
 84→        throw new ConflictException(
 85→          'You are already enrolled in this offering',
 86→        );
 87→      }
 88→
 89→      // Convert reservation
 90→      reservation.status = ReservationStatus.CONVERTED;
 91→      await manager.save(reservation);
 92→
 93→      // Create enrollment
 94→      const enrollment = manager.create(Enrollment, {
 95→        offeringId: reservation.offeringId,
 96→        userId,
 97→        reservationId,
 98→        status: EnrollmentStatus.CONFIRMED,
 99→        confirmedAt: new Date(),
100→        idempotencyKey,
101→      });
102→      const saved = await manager.save(enrollment);
103→
104→      // Record transitions
105→      await manager.save(
106→        manager.create(EnrollmentStateTransition, {
107→          reservationId,
108→          fromState: 'HELD',
109→          toState: 'CONVERTED',
110→          actorId: userId,
111→          traceId: getTraceId(),
112→          reason: 'Reservation confirmed',
113→        }),
114→      );
115→      await manager.save(
116→        manager.create(EnrollmentStateTransition, {
117→          enrollmentId: saved.id,
118→          fromState: 'NONE',
119→          toState: 'CONFIRMED',
120→          actorId: userId,
121→          traceId: getTraceId(),
122→          reason: 'Enrollment confirmed from reservation',
123→        }),
124→      );
125→
126→      await this.auditService.recordEvent({
127→        action: 'enrollment.confirm',
128→        resourceType: 'enrollments',
129→        resourceId: saved.id,
130→        actorId: userId,
131→      });
132→
133→      const response = {
134→        id: saved.id,
135→        offeringId: saved.offeringId,
136→        status: saved.status,
137→        confirmedAt: saved.confirmedAt,
138→      };
139→
140→      await this.idempotencyService.store(
141→        idempotencyKey,
142→        'enrollments.confirm',
143→        userId,
144→        201,
145→        response,
146→      );
147→
148→      return response;
149→    });
150→  }
