235→  async approveEnrollment(
236→    enrollmentId: string,
237→    actorId: string,
238→    reason?: string,
239→  ) {
240→    return this.dataSource.transaction(async (manager) => {
241→      const enrollment = await manager
242→        .createQueryBuilder(Enrollment, 'e')
243→        .setLock('pessimistic_write')
244→        .where('e.id = :id', { id: enrollmentId })
245→        .getOne();
246→
247→      if (!enrollment) throw new NotFoundException('Enrollment not found');
248→      if (enrollment.status !== EnrollmentStatus.WAITLISTED) {
249→        throw new BadRequestException('Can only approve waitlisted enrollments');
250→      }
251→
252→      enrollment.status = EnrollmentStatus.APPROVED;
253→      enrollment.approvedAt = new Date();
254→      await manager.save(enrollment);
255→
256→      await manager.save(
257→        manager.create(EnrollmentStateTransition, {
258→          enrollmentId: enrollment.id,
259→          fromState: 'WAITLISTED',
260→          toState: 'APPROVED',
261→          actorId,
262→          traceId: getTraceId(),
263→          reason: reason || 'Enrollment approved',
264→        }),
265→      );
266→
267→      await this.auditService.recordEvent({
268→        action: 'enrollment.approve',
269→        resourceType: 'enrollments',
270→        resourceId: enrollmentId,
271→        actorId,
272→      });
273→
274→      return enrollment;
275→    });
276→  }
