278→  async findAll(query: {
279→    page?: number;
280→    pageSize?: number;
281→    offeringId?: string;
282→    status?: string;
283→    userId?: string;
284→  }) {
285→    const page = query.page || 1;
286→    const pageSize = Math.min(query.pageSize || 20, 100);
287→
288→    const qb = this.enrollmentRepo.createQueryBuilder('e');
289→    if (query.offeringId) qb.andWhere('e.offeringId = :oid', { oid: query.offeringId });
290→    if (query.status) qb.andWhere('e.status = :status', { status: query.status });
291→    if (query.userId) qb.andWhere('e.userId = :uid', { uid: query.userId });
292→
293→    qb.orderBy('e.createdAt', 'DESC');
294→    qb.skip((page - 1) * pageSize).take(pageSize);
295→
296→    const [items, total] = await qb.getManyAndCount();
297→    return { items, total, page, pageSize };
298→  }
299→
300→  async findById(id: string): Promise<Enrollment & { transitions?: EnrollmentStateTransition[] }> {
301→    const enrollment = await this.enrollmentRepo.findOne({ where: { id } });
302→    if (!enrollment) throw new NotFoundException('Enrollment not found');
303→
304→    const transitions = await this.transitionRepo.find({
305→      where: { enrollmentId: id },
306→      order: { timestamp: 'ASC' },
307→    });
308→
309→    return { ...enrollment, transitions };
310→  }
311→
312→  /**
313→   * Promote next waitlisted user for an offering. Called by job.
314→   */
315→  async promoteNextWaitlisted(offeringId: string): Promise<boolean> {
316→    return this.dataSource.transaction(async (manager) => {
317→      const offering = await manager
318→        .createQueryBuilder(Offering, 'o')
319→        .setLock('pessimistic_write')
320→        .where('o.id = :id', { id: offeringId })
321→        .getOne();
322→
323→      if (!offering || offering.seatsAvailable <= 0) return false;
324→
325→      const next = await manager
326→        .createQueryBuilder(Enrollment, 'e')
327→        .where('e.offeringId = :oid AND e.status = :status', {
328→          oid: offeringId,
329→          status: EnrollmentStatus.WAITLISTED,
330→        })
331→        .orderBy('e.waitlistedAt', 'ASC')
332→        .getOne();
333→
334→      if (!next) return false;
335→
336→      if (offering.requiresApproval) {
337→        next.status = EnrollmentStatus.APPROVED;
338→        next.approvedAt = new Date();
339→      } else {
340→        next.status = EnrollmentStatus.CONFIRMED;
341→        next.confirmedAt = new Date();
342→        // Decrement seat
343→        await manager
344→          .createQueryBuilder()
345→          .update(Offering)
346→          .set({ seatsAvailable: () => '"seatsAvailable" - 1' })
347→          .where('id = :id', { id: offeringId })
348→          .execute();
349→      }
350→      await manager.save(next);
351→
352→      await manager.save(
353→        manager.create(EnrollmentStateTransition, {
354→          enrollmentId: next.id,
355→          fromState: 'WAITLISTED',
356→          toState: next.status,
357→          actorId: '00000000-0000-0000-0000-000000000000',
358→          traceId: getTraceId(),
359→          reason: 'Auto-promoted from waitlist',
360→        }),
361→      );
362→
363→      return true;
364→    });
365→  }
366→}
